class Solution:
    def longestIdealString(self, s, k):
        n = len(s)
        dp = [1] * n
        best = 0
        for i in range(n):
            for j in range(i):
                if abs(ord(s[i]) - ord(s[j])) <= k:
                    if dp[j] + 1 > dp[i]:
                        dp[i] = dp[j] + 1
            if dp[i] > best:
                best = dp[i]
        return best if n else 0

