class Solution:
    def longestIdealString(self, s, k):
        best = [0] * 26
        for ch in s:
            c = ord(ch) - 97
            lo = max(0, c - k)
            hi = min(25, c + k)
            cur = 0
            for d in range(lo, hi + 1):
                if best[d] > cur:
                    cur = best[d]
            best[c] = cur + 1
        return max(best)

